   137|async function ensureBranch(token: string, repoSlug: string, branch: string): Promise<string> {
   138|  const ref = (await githubFetch(token, `/repos/${repoSlug}/git/ref/heads/${branch}`)) as
   139|    | { object: { sha: string } }
   140|    | null;
   141|  if (ref) return ref.object.sha;
