   145|    token,
   146|    `/repos/${repoSlug}/git/ref/heads/${repo.default_branch}`,
   147|  )) as { object: { sha: string } | null };
   148|  if (!defaultRef) throw new Error('Cannot find default branch');
   149|
   150|  await githubFetch(token, `/repos/${repoSlug}/git/refs`, {
