   181|async function createBlob(token: string, repoSlug: string, content: Uint8Array): Promise<string> {
   182|  // Convert Uint8Array to base64
   183|  let b64 = '';
   184|  const chunkSize = 0x8000;
   185|  for (let i = 0; i < content.length; i += chunkSize) {
   186|    const chunk = content.subarray(i, i + chunkSize);
   187|    b64 += String.fromCharCode(...chunk);
   188|  }
   189|  b64 = btoa(b64);
   190|
   191|  const result = (await githubFetch(token, `/repos/${repoSlug}/git/blobs`, {
   192|    method: 'POST',
   193|    body: JSON.stringify({ content: b64, encoding: 'base64' }),
   194|  })) as { sha: string };
   195|  return result.sha;
   196|}
