   242|// ── Fetch files from Rork git router ─────────────────────────────────────
   243|// We can't read the local filesystem from a Worker, but we CAN fetch the
   244|// code from Rork's git router which has the latest pushed code.
   245|
   246|const RORK_GIT_ROUTER = 'https://rork-git-router.rork-direct.workers.dev/git/vfzx7vkb6j1ojd73kgwif';
   247|
   248|async function getRorkGitHeadSha(): Promise<string> {
   249|  // Fetch the refs from the Rork git router
   250|  const res = await fetch(`${RORK_GIT_ROUTER}/info/refs?service=git-upload-pack`);
   251|  if (!res.ok) throw new Error(`Rork git router refs fetch failed: ${res.status}`);
   252|  const text = await res.text();
   253|  // Parse the git-upload-pack response to find HEAD sha
   254|  // Format: 001e# service=git-upload-pack\n0000<ref-list>
   255|  const lines = text.split('\n');
   256|  for (const line of lines) {
   257|    // Look for HEAD line: 0040<sha> HEAD\0...
   258|    const match = line.match(/([0-9a-f]{40}) HEAD/);
   259|    if (match) return match[1];
   260|  }
   261|  // Try to find refs/heads/main
   262|  for (const line of lines) {
   263|    const match = line.match(/([0-9a-f]{40}) refs\/heads\/main/);
   264|    if (match) return match[1];
   265|  }
   266|  throw new Error('Could not find HEAD SHA from Rork git router');
