   380|export default {
   381|  async fetch(request: Request, env: Env): Promise<Response> {
   382|    const startTime = Date.now();
   383|
   384|    if (request.method === 'OPTIONS') {
   385|      return jsonResponse({ ok: true }, 200);
   386|    }
   387|
   388|    if (request.method === 'GET') {
   389|      // Health check / status
   390|      const token = readTrimmed(env.GITHUB_TOKEN);
   391|      return jsonResponse({
   392|        ok: true,
   393|        service: 'ivx-deploy-bridge',
   394|        githubTokenPresent: token.length > 0,
   395|        githubTokenMask: maskToken(token),
   396|        githubTokenIsPlaceholder: token.toUpperCase().includes('PLACEHOLDER'),
   397|        renderApiKeyPresent: readTrimmed(env.RENDER_API_KEY).length > 0,
   398|        renderServiceIdPresent: readTrimmed(env.RENDER_SERVICE_ID).length > 0,
   399|        repoSlug: getRepoSlug(env) || '(not configured)',
   400|      });
   401|    }
   402|
   403|    if (request.method !== 'POST') {
   404|      return jsonResponse({ ok: false, error: 'Method not allowed' }, 405);
   405|    }
   406|
   407|    let body: { action?: string } = {};
   408|    try {
   409|      const text = await request.text();
   410|      if (text) body = JSON.parse(text) as { action?: string };
   411|    } catch {
   412|      // empty body is fine
   413|    }
   414|
   415|    const action = body.action || 'full-deploy';
   416|    const token = readTrimmed(env.GITHUB_TOKEN);
   417|    const renderKeyRaw = readTrimmed(env.RENDER_API_KEY);
   418|    const renderKey = extractRenderKey(renderKeyRaw);
   419|    const renderServiceId = readTrimmed(env.RENDER_SERVICE_ID) || DEFAULT_RENDER_SERVICE_ID;
   420|    const aiGatewayKeyRaw = readTrimmed(env.AI_GATEWAY_API_KEY);
   421|    const aiGatewayKey = extractVercelKey(aiGatewayKeyRaw);
   422|    const repoSlug = getRepoSlug(env);
   423|    const branch = readTrimmed(env.GITHUB_BRANCH) || 'main';
   424|
   425|    const envStatus = {
   426|      githubToken: {
   427|        present: token.length > 0,
   428|        length: token.length,
   429|        mask: maskToken(token),
   430|        isPlaceholder: token.toUpperCase().includes('PLACEHOLDER') || token === '',
   431|      },
   432|      renderApiKey: { present: renderKey.length > 0, length: renderKey.length },
   433|      renderServiceId: { present: renderServiceId.length > 0, length: renderServiceId.length },
   434|      repoSlug: repoSlug || '(not configured)',
   435|    };
   436|
   437|    try {
   438|      // ── Env presence check (no secrets returned) ──
   439|      if (action === 'env-check') {
   440|        return jsonResponse({
   441|          ok: true,
   442|          aiGatewayKey: {
   443|            present: aiGatewayKey.length > 0,
   444|            rawLength: aiGatewayKeyRaw.length,
   445|            cleanLength: aiGatewayKey.length,
   446|            mask: maskToken(aiGatewayKey),
   447|            looksValid: aiGatewayKey.startsWith('vck_'),
   448|          },
   449|          renderApiKey: {
   450|            present: renderKey.length > 0,
   451|            rawLength: renderKeyRaw.length,
   452|            cleanLength: renderKey.length,
   453|            mask: maskToken(renderKey),
   454|            looksValid: renderKey.startsWith('rnd_') && renderKey.length >= 20,
   455|          },
   456|          renderServiceId,
   457|          action,
   458|        });
   459|      }
   460|
   461|      // ── Validate Render key against Render API (server-side) ──
   462|      if (action === 'render-test') {
   463|        if (!renderKey) {
   464|          return jsonResponse({ ok: false, error: 'RENDER_API_KEY not available in Worker env', action });
   465|        }
   466|        const res = await fetch(`${RENDER_API}/services/${encodeURIComponent(renderServiceId)}`, {
   467|          headers: { Authorization: `Bearer ${renderKey}`, Accept: 'application/json' },
   468|        });
   469|        const text = await res.text();
   470|        if (!res.ok) {
   471|          return jsonResponse({ ok: false, status: res.status, error: text.slice(0, 300), keyMask: maskToken(renderKey), keyLength: renderKey.length, action });
   472|        }
   473|        const svc = JSON.parse(text) as { name?: string; suspended?: string };
   474|        return jsonResponse({ ok: true, status: res.status, serviceName: svc.name ?? null, suspended: svc.suspended ?? null, keyMask: maskToken(renderKey), action });
   475|      }
   476|
   477|      // ── Validate AI Gateway key against Vercel (server-side) ──
   478|      if (action === 'gateway-test') {
   479|        if (!aiGatewayKey) {
   480|          return jsonResponse({ ok: false, error: 'AI_GATEWAY_API_KEY not available in Worker env', action });
   481|        }
   482|        const result = await testAIGatewayKey(aiGatewayKey);
   483|        return jsonResponse({ ...result, action, elapsedMs: Date.now() - startTime });
   484|      }
   485|
   486|      // ── Bind AI_GATEWAY_API_KEY to Render service + deploy ──
   487|      if (action === 'render-set-ai-key') {
   488|        if (!aiGatewayKey) {
   489|          return jsonResponse({ ok: false, error: 'AI_GATEWAY_API_KEY not available in Worker env', action });
   490|        }
   491|        if (!renderKey) {
   492|          return jsonResponse({ ok: false, error: 'RENDER_API_KEY not available in Worker env', action });
   493|        }
   494|        const setResult = await setRenderEnvVar(renderKey, renderServiceId, 'AI_GATEWAY_API_KEY', aiGatewayKey);
   495|        const deployResult = setResult.ok === true
   496|          ? await triggerRenderDeploy(renderKey, renderServiceId)
   497|          : { ok: false, skipped: true };
   498|        return jsonResponse({
   499|          ok: setResult.ok === true && deployResult.ok === true,
   500|          envVarSet: setResult,
   501|          deploy: deployResult,
   502|          serviceId: renderServiceId,
   503|          action,
   504|          elapsedMs: Date.now() - startTime,
   505|        });
   506|      }
   507|
   508|      // ── Render deploy status ──
   509|      if (action === 'render-deploy-status') {
   510|        const deployId = readTrimmed((body as { deployId?: string }).deployId);
   511|        if (!renderKey || !deployId) {
   512|          return jsonResponse({ ok: false, error: 'renderKey or deployId missing', action });
   513|        }
   514|        const result = await getRenderDeployStatus(renderKey, renderServiceId, deployId);
   515|        return jsonResponse({ ...result, action });
